Code.Terraform:
```hcl
resource "aws_sagemaker_model" "model" {
  name               = "<example_resource_name>"
  execution_role_arn = "<example_resource_id>"

  primary_container {
    image = "<example_resource_name>"
  }

  # 关键：VPC 配置为模型启用 VPC 网络，因此检查通过
  vpc_config {
    subnets            = ["<example_resource_id>"]       # 关键的
    security_group_ids = ["<example_resource_id>"]       # 关键的
  }
}
```
